   370→  /// @return updatedAt The timestamp of the latest price update.
   371→  /// @return isValid Whether the returned price is valid or not (non-zero and not stale).
   372→  function _getAssetPrice(
   373→    address asset,
   374→    bool withValidation
   375→  ) internal view virtual returns (uint256 price, uint256 updatedAt, bool isValid) {
   376→    DataStreamsPriceInfo memory priceInfo = s_dataStreamsPrice[asset];
   377→    FeedInfo memory feedInfo = s_feedInfo[asset];
   378→    uint256 minTimestamp = block.timestamp - feedInfo.stalenessThreshold;
